import numpy as np

def erosion(image, structuring_element):
  eroded_image = np.zeros(image.shape)
  for i in range(image.shape[0]):
    for j in range(image.shape[1]):
      if np.all(image[i:i+structuring_element.shape[0], j:j+structuring_element.shape[1]] == structuring_element):
        eroded_image[i+structuring_element.shape[0]//2, j+structuring_element.shape[1]//2] = 1
  return eroded_image

