void dilation(int **image, int **structuring_element, int **dilated_image, int n, int m) {
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < m; j++) {
      if (image[i][j] == 1) {
        for (int k = 0; k < 3; k++) {
          for (int l = 0; l < 3; l++) {
            if (structuring_element[k][l] == 1) {
              dilated_image[i+k-1][j+l-1] = 1;
            }
          }
        }
      }
    }
  }
}
